import { Component, OnDestroy } from '@angular/core';
import { Observable, Subject, of, timer, throwError } from 'rxjs';
import {
  catchError,
  debounceTime,
  map,
  switchMap,
  takeUntil,
  tap,
} from 'rxjs/operators';

interface Result {
  id: number;
  name: string;
  email: string;
}

type SearchStatus = 'idle' | 'loading' | 'success' | 'empty' | 'error';

interface SearchOutcome {
  term: string;
  status: SearchStatus;
  results: Result[];
  error: string | null;
}

const FAKE_DATA: Result[] = [
  { id: 1, name: 'Alice Johnson', email: 'alice@example.com' },
  { id: 2, name: 'Bob Smith', email: 'bob@example.com' },
  { id: 3, name: 'Charlie Kim', email: 'charlie@example.com' },
  { id: 4, name: 'Diana Lopez', email: 'diana@example.com' },
  { id: 5, name: 'Ethan Brown', email: 'ethan@example.com' },
  { id: 6, name: 'Fiona Patel', email: 'fiona@example.com' }
];

@Component({
  selector: 'app-root',
  standalone: true,
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnDestroy {
  query = '';
  results: Result[] = [];
  status: SearchStatus = 'idle';
  error: string | null = null;

  private readonly searchTerm$ = new Subject<string>();
  private readonly cancelActiveRequest$ = new Subject<void>();
  private readonly destroy$ = new Subject<void>();

  constructor() {
    this.setupSearchStream();
  }

  get isLoading(): boolean {
    return this.status === 'loading';
  }

  onQueryChange(value: string): void {
    this.query = value;
    this.searchTerm$.next(value);
  }

  ngOnDestroy(): void {
    this.cancelActiveRequest$.next();
    this.destroy$.next();
    this.cancelActiveRequest$.complete();
    this.destroy$.complete();
    this.searchTerm$.complete();
  }

  private setupSearchStream(): void {
    this.searchTerm$
      .pipe(
        tap((rawTerm) => {
          this.cancelActiveRequest$.next();
          this.results = [];
          this.error = null;
          this.status = rawTerm.trim() ? 'loading' : 'idle';
        }),
        map((term) => term.trim()),
        debounceTime(500),
        switchMap((term) => {
          if (!term) {
            return of<SearchOutcome>({
              term,
              status: 'idle',
              results: [],
              error: null,
            });
          }

          return this.fakeApiSearch(term).pipe(
            takeUntil(this.cancelActiveRequest$),
            map((results): SearchOutcome => ({
              term,
              status: results.length ? 'success' : 'empty',
              results,
              error: null,
            })),
            catchError((reason: unknown) => of<SearchOutcome>({
              term,
              status: 'error',
              results: [],
              error: reason instanceof Error ? reason.message : 'Something went wrong.',
            }))
          );
        }),
        takeUntil(this.destroy$)
      )
      .subscribe((outcome) => {
        if (outcome.term !== this.query.trim()) return;
        this.results = outcome.results;
        this.error = outcome.error;
        this.status = outcome.status;
      });
  }

  private fakeApiSearch(term: string): Observable<Result[]> {
    const normalized = term.trim().toLowerCase();
    const filtered = FAKE_DATA.filter((item) => {
      const name = item.name.toLowerCase();
      const email = item.email.toLowerCase();
      return name.includes(normalized) || email.includes(normalized);
    });

    if (normalized === 'error') {
      return timer(600).pipe(
        switchMap(() => throwError(() => new Error('Fake API error')))
      );
    }

    return timer(600).pipe(map(() => filtered));
  }
}
